SELECT elec_motor_id, elec_motor_tag, elec_motor_process, elec_motor_model, elec_motor_rated_power, elec_motor_rated_voltage, elec_motor_rated_current, elec_motor_rated_freq, elec_motor_speed, elec_motor_power_factor, elec_motor_efficiency, elec_motor_wiring_mode, elec_motor_bearing_model, elec_motor_explosion_mark, elec_motor_insulation, elec_motor_protection, elec_motor_work_system, elec_motor_factory_no, elec_motor_weight, elec_motor_prod_date, elec_motor_manufacturer FROM elec_motor
AND elec_motor_tag LIKE CONCAT('%', #{queryParams.elecMotorTag}, '%')
AND elec_motor_prod_date >= #{startDate}
AND elec_motor_prod_date <= #{endDate}
AND elec_motor_manufacturer = #{queryParams.elecMotorManufacturer}

SELECT elec_motor_tag, elec_motor_process, elec_motor_model, elec_motor_rated_power, elec_motor_rated_voltage, elec_motor_rated_current, elec_motor_rated_freq, elec_motor_speed, elec_motor_power_factor, elec_motor_efficiency, elec_motor_wiring_mode, elec_motor_bearing_model, elec_motor_explosion_mark, elec_motor_insulation, elec_motor_protection, elec_motor_work_system, elec_motor_factory_no, elec_motor_weight, elec_motor_prod_date, elec_motor_manufacturer FROM elec_motor
AND elec_motor_tag LIKE CONCAT('%', #{elecMotorTag}, '%')
AND elec_motor_prod_date >= #{startDate}
AND elec_motor_prod_date <= #{endDate}
AND elec_motor_manufacturer = #{elecMotorManufacturer}
